output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(MIN(?duration) AS ?min_duration) WHERE {
  VALUES ?series {
    wd:Q1004352 wd:Q1004228 wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P361 ?game .
  ?game wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840 ; wdt:P2047 ?duration .
  FILTER(DATATYPE(?duration) = xsd:integer || DATATYPE(?duration) = xsd:decimal)
}

args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT (MIN(?duration) AS ?min_duration)
WHERE {
  VALUES ?series {
    wd:Q1004352  # 1977 NLCS
    wd:Q1004228  # 1978 NLCS
    wd:Q3511262  # 2008 NLCS
    wd:Q3511261  # 2009 NLCS
  }
  ?game wdt:P361 ?series;
        wdt:P710 wd:Q334634;  # Los Angeles Dodgers
        wdt:P710 wd:Q650840;  # Philadelphia Phillies
        wdt:P2047 ?duration.
  FILTER (isNumeric(?duration))
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT (MIN(?duration) AS ?min_duration)
WHERE {
  VALUES ?series {
    wd:Q1004352  # 1977 NLCS
    wd:Q1004228  # 1978 NLCS
    wd:Q3511262  # 2008 NLCS
    wd:Q3511261  # 2009 NLCS
  }
  ?series wdt:P580 ?start;
            wdt:P582 ?end.
  ?game wdt:P585 ?date;
        wdt:P710 wd:Q334634;
        wdt:P710 wd:Q650840;
        wdt:P2047 ?duration.
  FILTER (?date >= ?start && ?date <= ?end)
  FILTER (isNumeric(?duration))
}
